{"code": "import json
import pandas as pd

# Read packages data - check if it's a file path
package_data = var_functions.query_db_6

if isinstance(package_data, str) and package_data.endswith('.json'):
    with open(package_data, 'r') as f:
        packages = json.load(f)
else:
    packages = package_data

# Extract NPM packages and their latest versions
npm_versions = {}
for record in packages:
    if record.get('System') == 'NPM':
        version_info = record.get('VersionInfo', '')
        try:
            # Parse the VersionInfo JSON
            clean_json = version_info.replace('\n', '').replace('\r', '').strip()
            parsed = json.loads(clean_json)

            if parsed.get('IsRelease'):
                name = record['Name']
                ordinal = parsed.get('Ordinal', 0)
                version = record['Version']

                # Keep only the highest ordinal (latest release) for each package
                if name not in npm_versions or ordinal > npm_versions[name]['Ordinal']:
                    npm_versions[name] = {'Version': version, 'Ordinal': ordinal}
        except:
            continue

# Convert to list of dicts for easier handling
latest_packages = [{'Name': name, 'Version': info['Version'], 'Ordinal': info['Ordinal']} 
                   for name, info in npm_versions.items()]

print('__RESULT__:')
print(json.dumps(latest_packages))"}

{"code": "import json
import pandas as pd
import re

# Load data from previous queries
package_result = locals()['var_functions.query_db:6']
projectpackage_result = locals()['var_functions.query_db:24']
projectinfo_result = locals()['var_functions.query_db:9']

# Helper to load JSON data whether it's a file path or direct data
def load_data(var):
    if isinstance(var, str) and var.endswith('.json'):
        with open(var, 'r') as f:
            return json.load(f)
    else:
        return var

packages = load_data(package_result)
project_packages = load_data(projectpackage_result)
project_info = load_data(projectinfo_result)

# Parse package data to find latest releases per package
package_data = []
for pkg in packages:
    if pkg.get('System') == 'NPM':
        try:
            version_info = json.loads(pkg['VersionInfo'])
            if version_info.get('IsRelease'):
                package_data.append({
                    'System': 'NPM',
                    'Name': pkg['Name'],
                    'Version': pkg['Version'],
                    'Ordinal': version_info.get('Ordinal', 0)
                })
        except:
            continue

# Find latest release for each package
pkg_df = pd.DataFrame(package_data)
if pkg_df.empty:
    print('__RESULT__:')
    print(json.dumps([]))
else:
    latest_idx = pkg_df.groupby('Name')['Ordinal'].idxmax()
    latest_packages = pkg_df.loc[latest_idx]

    # Load project package mappings
    proj_pkg_df = pd.DataFrame(project_packages)
    proj_pkg_df = proj_pkg_df[proj_pkg_df['System'] == 'NPM']

    # Merge with latest packages to get project names
    merged = latest_packages.merge(
        proj_pkg_df[['System', 'Name', 'Version', 'ProjectName']],
        on=['System', 'Name', 'Version'],
        how='inner'
    )

    # Extract star counts from project info
    stars_data = []
    for proj in project_info:
        info_text = proj.get('Project_Information', '')

        # Look for star patterns like "X stars" or "X stars,"
        star_match = re.search(r'(\d[\d,]*)\s+stars', info_text, re.IGNORECASE)
        if star_match:
            stars = int(star_match.group(1).replace(',', ''))
            stars_data.append({
                'ProjectName': proj.get('ProjectName', ''),
                'Stars': stars
            })

    if stars_data:
        stars_df = pd.DataFrame(stars_data)
        # Merge with package data
        final_df = merged.merge(stars_df, on='ProjectName', how='inner')

        # Sort by stars descending and get top 5
        if not final_df.empty:
            top5 = final_df.sort_values('Stars', ascending=False).head(5)
            result = top5.to_dict('records')
        else:
            result = []
    else:
        result = []

    print('__RESULT__:')
    print(json.dumps(result, default=str))"}

