        version_info = record.get('VersionInfo', '')
        try:
            # Parse the VersionInfo JSON
            clean_json = version_info.replace('\n', '').replace('\r', '').strip()
            parsed = json.loads(clean_json)

            if parsed.get('IsRelease'):
                name = record['Name']
                ordinal = parsed.get('Ordinal', 0)
                version = record['Version']

                # Keep only the highest ordinal (latest release) for each package
                if name not in npm_versions or ordinal > npm_versions[name]['Ordinal']:
                    npm_versions[name] = {'Version': version, 'Ordinal': ordinal}
